#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=200005;
ll n,a[N],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>ans;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	bool flag=(n%2==0);
	for(int l=1,r=n,cnt=1;cnt<=n;cnt++)
	{
//		cout<<l<<' '<<r<<"\n";
		if(flag)
		{
			ans=2*a[l]-ans;
			l++;
		}
		else
		{
			ans=2*a[r]-ans;
			r--;
		}
		flag=!flag;
	}
	cout<<ans;
	return 0;
}
